// src/pages/Groups.jsx
import { useEffect, useState } from 'react';
import { fetchGroups } from '../services/api';  // Fonction pour récupérer les groupes
import GroupCard from '../components/GroupCards'; 
import CreateGroup from '../components/GroupCreate';
import { GoogleMap, LoadScript, Marker } from '@react-google-maps/api';

import '../styles/Groups.css';

export default function Groups() {
    const [groups, setGroups] = useState([]);
    const [showModal, setShowModal] = useState(false);

    useEffect(() => {
        fetchGroups().then(setGroups);  // Récupère les groupes (les destinations)
    }, []);

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">Nos Groupes</h1>

                <button
                    className="create-group-button"
                    onClick={() => setShowModal(true)}
                >
                    Créer un Groupe
                </button>
            </div>
            <LoadScript googleMapsApiKey="TA_CLE_API" libraries={['places']}>
            <GoogleMap
            mapContainerStyle={{ width: '100%', height: '400px', marginBottom: '20px' }}
            center={{ lat: 48.8566, lng: 2.3522 }} // Centré par défaut sur Paris
            zoom={5}
            >
            {groups.map((group, i) =>
            group.location && group.location.lat && group.location.lng && (
                <Marker
                    key={i}
                    position={{ lat: group.location.lat, lng: group.location.lng }}
                    title={group.name}
                />
            )
            )}
            </GoogleMap>
            </LoadScript>


            <div className="groups-grid">
            {groups.map(group => (
        <GroupCard
            key={group.id}
            id={group.id}
            name={group.name}
            creator={group.creator}
            members={group.members}
        />
    ))}
</div>


            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
                        <CreateGroup onClose={() => setShowModal(false)} />
                    </div>
                </div>
            )}
        </div>
    );
}
